            position: "bottom",
          },
          {
            targetId: "onboarding-pro-card",
            title: "Upgrade to Pro",
            description:
              "Unlock infinite generation limits and exclusive models.",
            position: "right",
          },
        ]}
      />
      <PerformanceOptimizer />
    </div>
  );
}
